require("dotenv").config();
const express = require("express");
const cors = require("cors");
// const helmet = require('helmet');

const admin = require("firebase-admin");
const serviceAccount = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT);

admin.initializeApp({
  credential: admin.credential.cert(serviceAccount),
});

const aiRoutes = require("./routes/ai");
const stripeRoutes = require("./routes/stripe");
const imageRoutes = require("./routes/imageGeneration");
const oauthRoutes = require("./routes/oauth");
const instagramWebhook = require("./routes/instagramWebhook");


const app = express();
app.set('trust proxy', 1); // Required for Render (proxy) — fixes express-rate-limit X-Forwarded-For error
const PORT = process.env.PORT || 5000;


/* ===============================
   🔥 CORS CONFIG (PRODUCTION READY)
================================ */

const allowedOrigins = [
  "http://localhost:3000",
  "http://127.0.0.1:3000",
  "https://gormaran-growth-hub-1.onrender.com", // frontend
  "https://gormaran-growth-hub.onrender.com",   // backend
  "https://gormaran.io",
  "https://www.gormaran.io",
];

app.use(
  cors({
    origin: function (origin, callback) {
      if (!origin) return callback(null, true);

      if (allowedOrigins.includes(origin)) {
        callback(null, true);
      } else {
        callback(new Error("Not allowed by CORS"));
      }
    },
    credentials: true,
  })

